const y=(s,n)=>{const e={remember:{correct:0,total:0},understand:{correct:0,total:0},apply:{correct:0,total:0},analyze:{correct:0,total:0},evaluate:{correct:0,total:0},create:{correct:0,total:0}};s.forEach((t,a)=>{const r=t.level?.toLowerCase(),o=n[a];if(!r||!e[r]||!o||o==="Not answered")return;e[r].total++;let c=!1;typeof t.options=="object"&&!Array.isArray(t.options)?c=o===t.options[t.answer]:c=o===t.answer,c&&e[r].correct++});const l={};return Object.keys(e).forEach(t=>{const{correct:a,total:r}=e[t];l[t]=r>0?Math.round(a/r*100):0}),l};export{y as c};
